namespace SiteInspector.Client.Models;

/// <summary>
/// Default safety checklist template for construction site inspections.
/// </summary>
public static class ChecklistTemplates
{
    public static List<ChecklistItem> GetStandardChecklist() => new()
    {
        // Personal Protective Equipment
        new() { Category = "PPE", Description = "Hard hats worn by all personnel" },
        new() { Category = "PPE", Description = "Safety vests/high-visibility clothing" },
        new() { Category = "PPE", Description = "Safety boots with steel toe caps" },
        new() { Category = "PPE", Description = "Eye protection where required" },
        new() { Category = "PPE", Description = "Hearing protection where required" },

        // Fall Protection
        new() { Category = "Fall Protection", Description = "Guardrails in place at height" },
        new() { Category = "Fall Protection", Description = "Safety nets installed where required" },
        new() { Category = "Fall Protection", Description = "Harnesses worn for elevated work" },
        new() { Category = "Fall Protection", Description = "Ladder safety (secured, correct angle)" },

        // Housekeeping
        new() { Category = "Housekeeping", Description = "Walkways clear of obstructions" },
        new() { Category = "Housekeeping", Description = "Materials stored properly" },
        new() { Category = "Housekeeping", Description = "Waste disposed correctly" },
        new() { Category = "Housekeeping", Description = "No trip hazards present" },

        // Electrical Safety
        new() { Category = "Electrical", Description = "Temporary wiring in good condition" },
        new() { Category = "Electrical", Description = "GFCIs on all temporary power" },
        new() { Category = "Electrical", Description = "Lockout/tagout procedures followed" },

        // Scaffolding
        new() { Category = "Scaffolding", Description = "Scaffold fully planked" },
        new() { Category = "Scaffolding", Description = "Scaffold tied to structure" },
        new() { Category = "Scaffolding", Description = "Scaffold tag current and visible" },
        new() { Category = "Scaffolding", Description = "Access ladder provided" },

        // Fire Safety
        new() { Category = "Fire Safety", Description = "Fire extinguishers accessible" },
        new() { Category = "Fire Safety", Description = "Hot work permit displayed" },
        new() { Category = "Fire Safety", Description = "Flammable materials stored safely" },

        // Excavations
        new() { Category = "Excavations", Description = "Excavation edges protected" },
        new() { Category = "Excavations", Description = "Shoring/sloping adequate" },
        new() { Category = "Excavations", Description = "Spoil stored away from edge" },

        // Signage & Barriers
        new() { Category = "Signage", Description = "Site perimeter secure" },
        new() { Category = "Signage", Description = "Warning signs posted" },
        new() { Category = "Signage", Description = "Emergency exits clearly marked" },
    };
}

