using System.Text.Json;
using Microsoft.JSInterop;
using SiteInspector.Client.Models;

namespace SiteInspector.Client.Services;

/// <summary>
/// Provides offline-first data storage using IndexedDB via JS interop.
/// </summary>
public class InspectionStore : IAsyncDisposable
{
    private readonly IJSRuntime _js;
    private IJSObjectReference? _module;

    private static readonly JsonSerializerOptions JsonOptions = new()
    {
        PropertyNamingPolicy = JsonNamingPolicy.CamelCase
    };

    public InspectionStore(IJSRuntime js)
    {
        _js = js;
    }

    private async Task<IJSObjectReference> GetModuleAsync()
    {
        _module ??= await _js.InvokeAsync<IJSObjectReference>("import", "./js/indexedDb.js");
        return _module;
    }

    // Sites
    public async Task SaveSiteAsync(ConstructionSite site)
    {
        var module = await GetModuleAsync();
        var json = JsonSerializer.Serialize(site, JsonOptions);
        var obj = JsonSerializer.Deserialize<object>(json, JsonOptions);
        await module.InvokeVoidAsync("saveItem", "sites", obj);
    }

    public async Task<List<ConstructionSite>> GetAllSitesAsync()
    {
        var module = await GetModuleAsync();
        return await module.InvokeAsync<List<ConstructionSite>>("getAllItems", "sites");
    }

    public async Task<ConstructionSite?> GetSiteAsync(string id)
    {
        var module = await GetModuleAsync();
        return await module.InvokeAsync<ConstructionSite?>("getItem", "sites", id);
    }

    public async Task DeleteSiteAsync(string id)
    {
        var module = await GetModuleAsync();
        await module.InvokeVoidAsync("deleteItem", "sites", id);
    }

    // Inspections
    public async Task SaveInspectionAsync(Inspection inspection)
    {
        var module = await GetModuleAsync();
        var json = JsonSerializer.Serialize(inspection, JsonOptions);
        var obj = JsonSerializer.Deserialize<object>(json, JsonOptions);
        await module.InvokeVoidAsync("saveItem", "inspections", obj);
    }

    public async Task<List<Inspection>> GetAllInspectionsAsync()
    {
        var module = await GetModuleAsync();
        return await module.InvokeAsync<List<Inspection>>("getAllItems", "inspections");
    }

    public async Task<Inspection?> GetInspectionAsync(string id)
    {
        var module = await GetModuleAsync();
        return await module.InvokeAsync<Inspection?>("getItem", "inspections", id);
    }

    public async Task<List<Inspection>> GetUnsyncedInspectionsAsync()
    {
        var module = await GetModuleAsync();
        return await module.InvokeAsync<List<Inspection>>("getUnsyncedInspections");
    }

    public async Task DeleteInspectionAsync(string id)
    {
        var module = await GetModuleAsync();
        await module.InvokeVoidAsync("deleteItem", "inspections", id);
    }

    // Connectivity
    public async Task<bool> IsOnlineAsync()
    {
        var module = await GetModuleAsync();
        return await module.InvokeAsync<bool>("isOnline");
    }

    public async Task RegisterOnlineListenerAsync(DotNetObjectReference<SyncService> dotNetRef)
    {
        var module = await GetModuleAsync();
        await module.InvokeVoidAsync("registerOnlineListener", dotNetRef);
    }

    public async Task UnregisterOnlineListenerAsync()
    {
        var module = await GetModuleAsync();
        await module.InvokeVoidAsync("unregisterOnlineListener");
    }

    public async ValueTask DisposeAsync()
    {
        if (_module is not null)
        {
            await _module.DisposeAsync();
        }
    }
}

