                            @GetSummary(inspection)
                        </div>
                    </div>
                    <span class="chevron">›</span>
                </div>
            }
        </div>
    }
}

@code {
    [Parameter] public string SiteId { get; set; } = string.Empty;

    private ConstructionSite? _site;
    private List<Inspection> _inspections = new();

    protected override async Task OnInitializedAsync()
    {
        _site = await Store.GetSiteAsync(SiteId);
        var allInspections = await Store.GetAllInspectionsAsync();
        _inspections = allInspections.Where(i => i.SiteId == SiteId).ToList();
    }

    private async Task StartNewInspection()
    {
        var inspection = new Inspection
        {
            SiteId = SiteId,
            SiteName = _site?.Name ?? "",
            ChecklistItems = ChecklistTemplates.GetStandardChecklist()
        };

        await Store.SaveInspectionAsync(inspection);
        Nav.NavigateTo($"/inspection/{inspection.Id}");
    }

    private void OpenInspection(string id)
    {
        Nav.NavigateTo($"/inspection/{id}");
    }

    private string GetStatusClass(Inspection inspection) =>
        inspection.Status == InspectionStatus.Completed ? "badge-completed" : "badge-progress";

    private string GetSummary(Inspection inspection)
    {
        var total = inspection.ChecklistItems.Count;
        var checked_ = inspection.ChecklistItems.Count(c => c.Result != CheckResult.NotChecked);
        var failed = inspection.ChecklistItems.Count(c => c.Result == CheckResult.Fail);
        return $"{checked_}/{total} checked • {failed} failed • {inspection.Photos.Count} photos";
    }
}

