@using SiteInspector.Client.Models
@using SiteInspector.Client.Services
@inject InspectionStore Store
@inject SyncService Sync
@inject NavigationManager Nav

<PageTitle>Inspection</PageTitle>

@if (_inspection is null)
{
    <p class="loading">Loading inspection...</p>
}
else
{
    <div class="page-header">
        <button class="btn-back" @onclick="GoBack">← Back</button>
        <h1>Inspection</h1>
        @if (_inspection.Status == InspectionStatus.InProgress)
        {
            <button class="btn-complete" @onclick="CompleteInspection">✓ Complete</button>
        }
    </div>

    <div class="tab-bar">
        <button class="tab @(_activeTab == "checklist" ? "active" : "")" @onclick='() => _activeTab = "checklist"'>
            Checklist
        </button>
        <button class="tab @(_activeTab == "photos" ? "active" : "")" @onclick='() => _activeTab = "photos"'>
            Photos (@_inspection.Photos.Count)
        </button>
        <button class="tab @(_activeTab == "notes" ? "active" : "")" @onclick='() => _activeTab = "notes"'>
            Notes
        </button>
    </div>

    @if (_activeTab == "checklist")
    {
        <div class="checklist">
            @foreach (var category in _inspection.ChecklistItems.GroupBy(c => c.Category))
            {
                <div class="checklist-category">
                    <h3>@category.Key</h3>
                    @foreach (var item in category)
                    {
                        <div class="checklist-item @GetItemClass(item)">
                            <div class="item-description">@item.Description</div>
                            <div class="item-actions">
                                <button class="result-btn pass @(item.Result == CheckResult.Pass ? "selected" : "")"
                                        @onclick="() => SetResult(item, CheckResult.Pass)" title="Pass">✓</button>
                                <button class="result-btn fail @(item.Result == CheckResult.Fail ? "selected" : "")"
                                        @onclick="() => SetResult(item, CheckResult.Fail)" title="Fail">✗</button>
                                <button class="result-btn na @(item.Result == CheckResult.NotApplicable ? "selected" : "")"
                                        @onclick="() => SetResult(item, CheckResult.NotApplicable)" title="N/A">—</button>
                            </div>
                            @if (item.Result == CheckResult.Fail)
                            {
                                <input class="item-note" placeholder="Add note about failure..."
                                       value="@item.Notes"
                                       @onchange="(e) => SetItemNote(item, e.Value?.ToString() ?? "")" />
                            }
                        </div>
                    }
                </div>
            }
        </div>
    }
    else if (_activeTab == "photos")
    {
        <div class="photos-section">
            <label class="btn-primary btn-full photo-capture-btn">
                📷 Take Photo
                <InputFile OnChange="OnPhotoSelected" accept="image/*" capture="environment" style="display:none" />
            </label>

            @if (_inspection.Photos.Count == 0)
            {
                <div class="empty-state">
                    <p>No photos yet. Tap the button above to capture.</p>
                </div>
            }
            else
            {
                <div class="photo-grid">
                    @foreach (var photo in _inspection.Photos.OrderByDescending(p => p.TakenAt))
                    {
                        <div class="photo-card">
                            <img src="data:image/jpeg;base64,@photo.DataBase64" alt="@photo.Caption" />
                            <input class="photo-caption" placeholder="Add caption..."
                                   value="@photo.Caption"
                                   @onchange="(e) => SetPhotoCaption(photo, e.Value?.ToString() ?? "")" />
                            <button class="btn-delete-photo" @onclick="() => RemovePhoto(photo)">Remove</button>
                        </div>
                    }
                </div>
            }
        </div>
    }
    else if (_activeTab == "notes")
    {
        <div class="notes-section">
            <textarea class="notes-input" placeholder="Add inspection notes..."
                      @bind="_inspection.Notes" @bind:event="oninput" @bind:after="SaveAsync"></textarea>
            <div class="inspector-field">
                <label>Inspector Name</label>
                <input class="input-field" placeholder="Your name"
                       @bind="_inspection.InspectorName" @bind:event="oninput" @bind:after="SaveAsync" />
            </div>
        </div>
    }
}

@code {
    [Parameter] public string InspectionId { get; set; } = string.Empty;

    private Inspection? _inspection;
    private string _activeTab = "checklist";

    protected override async Task OnInitializedAsync()
    {
        _inspection = await Store.GetInspectionAsync(InspectionId);
    }

    private async Task SetResult(ChecklistItem item, CheckResult result)
    {
        item.Result = item.Result == result ? CheckResult.NotChecked : result;
        await SaveAsync();
    }

    private async Task SetItemNote(ChecklistItem item, string note)
    {
        item.Notes = note;
        await SaveAsync();
    }

    private async Task OnPhotoSelected(InputFileChangeEventArgs e)
    {
        var file = e.File;
        if (file is null) return;

        // Resize to max 1024px wide for storage efficiency
        var resized = await file.RequestImageFileAsync("image/jpeg", 1024, 1024);
        using var stream = resized.OpenReadStream(maxAllowedSize: 5 * 1024 * 1024);
        using var ms = new MemoryStream();
        await stream.CopyToAsync(ms);

        var photo = new InspectionPhoto
        {
            FileName = file.Name,
            DataBase64 = Convert.ToBase64String(ms.ToArray()),
            TakenAt = DateTime.UtcNow
        };

        _inspection!.Photos.Add(photo);
        await SaveAsync();
    }

    private async Task SetPhotoCaption(InspectionPhoto photo, string caption)
    {
        photo.Caption = caption;
        await SaveAsync();
    }

    private async Task RemovePhoto(InspectionPhoto photo)
    {
        _inspection!.Photos.Remove(photo);
        await SaveAsync();
    }

    private async Task CompleteInspection()
    {
        _inspection!.Status = InspectionStatus.Completed;
        await SaveAsync();
        await Sync.SyncAsync();
    }

    private async Task SaveAsync()
    {
        if (_inspection is null) return;
        _inspection.IsSynced = false;
        await Store.SaveInspectionAsync(_inspection);
        await Sync.UpdatePendingCountAsync();
    }

    private void GoBack()
    {
        Nav.NavigateTo($"/site/{_inspection?.SiteId}");
    }

    private string GetItemClass(ChecklistItem item) => item.Result switch
    {
        CheckResult.Pass => "item-pass",
        CheckResult.Fail => "item-fail",
        CheckResult.NotApplicable => "item-na",
        _ => ""
    };
}

