using Microsoft.AspNetCore.Components.WebAssembly.Hosting;
using SiteInspector.Client.Services;

var builder = WebAssemblyHostBuilder.CreateDefault(args);

builder.Services.AddScoped(sp =>
    new HttpClient { BaseAddress = new Uri(builder.HostEnvironment.BaseAddress) });
builder.Services.AddScoped<InspectionStore>();
builder.Services.AddScoped<SyncService>();

var host = builder.Build();

// Initialize sync service to start listening for connectivity changes
var syncService = host.Services.GetRequiredService<SyncService>();
await syncService.InitializeAsync();

await host.RunAsync();

